export const roomContaining = (
  rooms: readonly RoomRect[],
  position: Position,
): number | null => {
  for (let index = 0; index < rooms.length; index += 1) {
    const room = rooms[index];
    if (room === undefined) {
      continue;
    }

    if (
      position.x >= room.x &&
      position.x < room.x + room.width &&
      position.y >= room.y &&
      position.y < room.y + room.height
    ) {
      return index;
    }
  }

  return null;
};

